/* 文件头注释：模拟瑞士轮赛制，计算最多能有多少弱队进入八强 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int x;
    cin >> x;

    // 强队和弱队的数量
    int strong = 16 - x;
    int weak = x;

    // 模拟瑞士轮赛制
    // 第一轮：强队对弱队，强队必胜
    int strong_1_0 = strong;
    int weak_0_1 = weak;

    // 第二轮：1-0组强队互相对抗，0-1组弱队互相对抗
    int strong_2_0 = strong_1_0 / 2;
    int strong_1_1 = strong_1_0 - strong_2_0;
    int weak_1_1 = weak_0_1 / 2;
    int weak_0_2 = weak_0_1 - weak_1_1;

    // 第三轮：2-0组强队互相对抗，0-2组弱队互相对抗，1-1组继续BO1
    int strong_3_0 = strong_2_0 / 2;
    int strong_2_1 = strong_2_0 - strong_3_0;
    int weak_1_2 = weak_1_1 / 2;
    int weak_0_3 = weak_0_2;

    // 第四轮：2-1组强队互相对抗，1-2组弱队互相对抗
    int strong_3_1 = strong_2_1 / 2;
    int strong_2_2 = strong_2_1 - strong_3_1;
    int weak_2_2 = weak_1_2 / 2;
    int weak_1_3 = weak_1_2 - weak_2_2;

    // 第五轮：2-2组强队互相对抗，弱队互相对抗
    int strong_3_2 = strong_2_2 / 2;
    int weak_3_2 = (weak_2_2 + 1) / 2;  // 向上取整

    // 统计最终进入八强的弱队数量
    int weak_qualified = weak_3_2 + (weak_2_2 + 1) / 2;  // [FIX] 修正统计逻辑

    cout << weak_qualified << endl;

    return 0;
}
```

