/* 文件头注释：动态规划求解最大LCM问题 */
#include <bits/stdc++.h>
using namespace std;

// 计算两个数的最大公约数
int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

// 计算两个数的最小公倍数
int lcm(int a, int b) {
    return a / gcd(a, b) * b;
}

// 筛法预处理质数表
vector<int> getPrimes(int n) {
    vector<bool> isPrime(n + 1, true);
    vector<int> primes;
    for (int i = 2; i <= n; ++i) {
        if (isPrime[i]) {
            primes.push_back(i);
            for (int j = i * 2; j <= n; j += i) {
                isPrime[j] = false;
            }
        }
    }
    return primes;
}

int main() {
    int N;
    cin >> N;

    // 预处理质数表
    vector<int> primes = getPrimes(N);

    // dp[i]表示总和为i时的最大LCM
    vector<long long> dp(N + 1, 1);
    // path[i]记录总和为i时的数组
    vector<vector<int>> path(N + 1);

    // 采用贪心策略，从大数开始尝试
    for (int i = N; i >= 1; --i) {
        for (int j = 0; j < primes.size() && primes[j] <= i; ++j) {
            int p = primes[j];
            // 尝试p的幂次
            for (int k = p; k <= i; k *= p) {
                long long current_lcm = lcm(dp[i - k], k);
                if (current_lcm > dp[i]) {
                    dp[i] = current_lcm;
                    path[i] = path[i - k];
                    path[i].push_back(k);
                }
            }
        }
        // 最后尝试1
        long long current_lcm = lcm(dp[i - 1], 1);
        if (current_lcm > dp[i]) {
            dp[i] = current_lcm;
            path[i] = path[i - 1];
            path[i].push_back(1);
        }
    }

    // 输出结果，确保字典序最小
    sort(path[N].begin(), path[N].end());
    for (int num : path[N]) {
        cout << num << " ";
    }
    cout << endl;

    return 0;
}
```

