#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, s, t;
    cin >> n >> s >> t;
    vector<int> a(n), b(n);
    for (int i = 0; i < n; ++i) cin >> a[i];
    for (int i = 0; i < n; ++i) cin >> b[i];

    // 初始化DP数组，dp[j][k]表示从a中选择j个，从b中选择k个的最大得分
    vector<vector<int>> dp(s + 1, vector<int>(t + 1, -1));
    dp[0][0] = 0;

    for (int i = 0; i < n; ++i) {
        // 使用临时数组存储新的状态
        vector<vector<int>> new_dp(s + 1, vector<int>(t + 1, -1));
        for (int j = 0; j <= s; ++j) {
