#include <bits/stdc++.h>
using namespace std;

int main() {
    string balloons;
    cin >> balloons;
    int Q;
    cin >> Q;

    // 预处理每个位置的状态
    int n = balloons.size();
    vector<int> cntR(n + 1, 0); // cntR[i]表示前i个气球中红色气球的数量模3
    vector<int> cntG(n + 1, 0); // cntG[i]表示前i个气球中绿色气球的数量模3
    vector<int> cntB(n + 1, 0); // cntB[i]表示前i个气球中蓝色气球的数量模3

    for (int i = 1; i <= n; ++i) {
        cntR[i] = cntR[i - 1];
        cntG[i] = cntG[i - 1];
        cntB[i] = cntB[i - 1];
        if (balloons[i - 1] == 'R') {
            cntR[i] = (cntR[i] + 1) % 3;
        } else if (balloons[i - 1] == 'G') {
            cntG[i] = (cntG[i] + 1) % 3;
        } else if (balloons[i - 1] == 'B') {
            cntB[i] = (cntB[i] + 1) % 3;
        }
    }

    string result;
    for (int q = 0; q < Q; ++q) {
        int L, R;
        cin >> L >> R;
        int r = (cntR[R] - cntR[L - 1] + 3) % 3;
        int g = (cntG[R] - cntG[L - 1] + 3) % 3;
        int b = (cntB[R] - cntB[L - 1] + 3) % 3;

        // 判断是否可以通过替换操作最终变为单个红色气球
        if ((r == 1 && g == 0 && b == 0) || (r == 0 && g == 1 && b == 1) || (r == 2 && g == 2 && b == 2)) {
            result += 'Y';
        } else {
            result += 'N';
        }
    }

    cout << result << endl;
    return 0;
}

