/* 文件头注释：使用最远未来使用策略解决缓存替换问题 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    // 记录每个漫画的下一次出现时间
    unordered_map<int, queue<int>> next_use;
    for (int i = 0; i < n; ++i) {
        next_use[a[i]].push(i);
    }

    // 当前书桌上的漫画
    unordered_set<int> on_desk;
    // 优先队列，按未来使用时间排序
    priority_queue<pair<int, int>> pq;

    int cnt = 0;
    for (int i = 0; i < n; ++i) {
        // 如果当前漫画已经在书桌上，跳过
        if (on_desk.count(a[i])) {
            // 更新该漫画的下一次使用时间
            next_use[a[i]].pop();
            if (!next_use[a[i]].empty()) {
                pq.push({next_use[a[i]].front(), a[i]});
            }
            continue;
        }

        // 如果书桌已满，需要替换
        if (on_desk.size() == m) {
            // 找到未来最久才会被使用的漫画
            while (!pq.empty() && !on_desk.count(pq.top().second)) {
                pq.pop();
            }
            if (!pq.empty()) {
                int to_remove = pq.top().second;
                on_desk.erase(to_remove);
                pq.pop();
            }
        }

        // 将当前漫画放入书桌
        on_desk.insert(a[i]);
        next_use[a[i]].pop();
        if (!next_use[a[i]].empty()) {
            pq.push({next_use[a[i]].front(), a[i]});
        }
        cnt++;
    }

    cout << cnt << endl;
    return 0;
}

