/* 文件头注释：动态规划解决小Z的烧烤规划问题 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    // dp[i][j][k]表示在第i道菜时，当前卡路里上限为j，连续不吃次数为k时的最大总卡路里
    vector<vector<vector<int>>> dp(n + 1, vector<vector<int>>(m + 1, vector<int>(3, 0)));

    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= m; ++j) {
            for (int k = 0; k < 3; ++k) {
                // 不吃这道菜
                int new_skip = min(k + 1, 2);
                int new_limit = (new_skip == 2) ? m : j;
                dp[i][new_limit][new_skip] = max(dp[i][new_limit][new_skip], dp[i - 1][j][k]);

                // 吃这道菜
                if (a[i - 1] <= j) {
                    int new_limit_eat = j * 2 / 3;  // [FIX] 正确处理三分之二的减少和截断
                    dp[i][new_limit_eat][0] = max(dp[i][new_limit_eat][0], dp[i - 1][j][k] + a[i - 1]);
                }
            }
        }
    }

    // 找出最大值
    int max_calories = 0;
    for (int j = 1; j <= m; ++j) {
        for (int k = 0; k < 3; ++k) {
            max_calories = max(max_calories, dp[n][j][k]);
        }
    }

    cout << max_calories << endl;
    return 0;
}
```

