/* 文件头注释：动态规划解决带约束的背包问题，使用滚动数组优化空间复杂度 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, s, t;
    cin >> n >> s >> t;
    vector<int> a(n), b(n);
    for (int i = 0; i < n; ++i) cin >> a[i];
    for (int i = 0; i < n; ++i) cin >> b[i];

    // 使用两个一维数组作为滚动数组
    vector<vector<int>> dp(s + 1, vector<int>(t + 1, -1));
    dp[0][0] = 0;

    for (int i = 0; i < n; ++i) {
        // 从后向前更新，避免覆盖未使用的状态
        for (int j = s; j >= 0; --j) {
            for (int k = t; k >= 0; --k) {
                if (dp[j][k] == -1) continue; // 无效状态跳过
                // 不选择a[i]和b[i]
                // 选择a[i]
                if (j < s) dp[j + 1][k] = max(dp[j + 1][k], dp[j][k] + a[i]);
                // 选择b[i]
                if (k < t) dp[j][k + 1] = max(dp[j][k + 1], dp[j][k] + b[i]);
            }
        }
    }

    cout << dp[s][t] << endl;
    return 0;
}
```

