/* 文件头注释：使用改进的缓存替换策略，最小化取书次数 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    unordered_map<int, list<int>::iterator> cacheMap; // 哈希表，存储漫画编号和其在链表中的迭代器
    list<int> cacheList; // 双向链表，存储当前在书桌上的漫画编号
    int count = 0; // 记录取书次数

    // 预计算每个漫画的下一次出现位置
    unordered_map<int, int> nextUse;
    vector<int> lastPos(n + 1, n); // 初始化为n，表示最后一次出现的位置
    for (int i = n - 1; i >= 0; --i) {
        nextUse[i] = lastPos[a[i]];
        lastPos[a[i]] = i;
    }

    for (int i = 0; i < n; ++i) {
        int comic = a[i];
        if (cacheMap.find(comic) != cacheMap.end()) {
            // 如果漫画已经在书桌上，将其移到链表头部
            cacheList.erase(cacheMap[comic]);
            cacheList.push_front(comic);
            cacheMap[comic] = cacheList.begin();
        } else {
            // 如果漫画不在书桌上，需要从书架上取
            count++;
            if (cacheList.size() == m) {
                // 如果书桌已满，移除未来最久不会被使用的漫画
                int farthest = -1, toRemove = -1;
                for (auto it = cacheList.begin(); it != cacheList.end(); ++it) {
                    int next = nextUse[i];
                    if (next > farthest) {
                        farthest = next;
                        toRemove = *it;
                    }
                }
                cacheMap.erase(toRemove);
                cacheList.remove(toRemove);
            }
            // 将新漫画添加到链表头部
            cacheList.push_front(comic);
            cacheMap[comic] = cacheList.begin();
        }
    }

    cout << count << endl;
    return 0;
}
