/* 文件头注释：动态规划求解最大LCM问题 */
#include <bits/stdc++.h>
using namespace std;

// 计算最大公约数
int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

// 计算最小公倍数
int lcm(int a, int b) {
    return a * b / gcd(a, b);
}

int main() {
    int N;
    cin >> N;

    // dp[i]表示总和为i时的最大LCM
    vector<int> dp(N + 1, 1);
    // path[i]表示总和为i时的最优解
    vector<vector<int>> path(N + 1);

    for (int i = 1; i <= N; ++i) {
        for (int j = 1; j <= i; ++j) {
            int current_lcm = lcm(dp[i - j], j);
            if (current_lcm > dp[i]) {
                dp[i] = current_lcm;
                path[i] = path[i - j];
                path[i].push_back(j);
            }
        }
    }

    // 输出字典序最小的解
    sort(path[N].begin(), path[N].end());
    for (int i = 0; i < path[N].size(); ++i) {
        cout << path[N][i] << " ";
    }
    cout << endl;

    return 0;
}

