/* 文件头注释：说明核心算法名称和关键技术 */
#include <bits/stdc++.h>
using namespace std;

// 视频编码函数
vector<vector<int>> encodeVideo(int t, int n, int m, vector<vector<vector<int>>>& video) {
    // 卷积操作，将时间维度压缩为t/4
    int new_t = t / 4;
    int new_n = n / 4;
    int new_m = m / 4;
    vector<vector<vector<int>>> conv_video(3, vector<vector<int>>(new_n, vector<int>(new_m, 0)));

    for (int c = 0; c < 3; ++c) {
        for (int i = 0; i < new_n; ++i) {
            for (int j = 0; j < new_m; ++j) {
                for (int ti = 0; ti < 4; ++ti) {
                    for (int ni = 0; ni < 4; ++ni) {
                        for (int mi = 0; mi < 4; ++mi) {
                            conv_video[c][i][j] += video[ti * 4 + ni][c][i * 4 + ni][j * 4 + mi];
                        }
                    }
                }
            }
        }
    }

    // 拉平操作
    vector<vector<int>> flat_video(3, vector<int>(new_t * new_n * new_m, 0));
    for (int c = 0; c < 3; ++c) {
        int idx = 0;
        for (int ti = 0; ti < new_t; ++ti) {
            for (int ni = 0; ni < new_n; ++ni) {
                for (int mi = 0; mi < new_m; ++mi) {
                    flat_video[c][idx++] = conv_video[c][ni][mi];
                }
            }
        }
    }

    // 转置操作
    vector<vector<int>> transposed_video(new_t * new_n * new_m, vector<int>(3, 0));
    for (int i = 0; i < new_t * new_n * new_m; ++i) {
        for (int c = 0; c < 3; ++c) {
            transposed_video[i][c] = flat_video[c][i];
        }
    }

    // 添加cls token
    transposed_video.insert(transposed_video.begin(), vector<int>(3, 0));

    return transposed_video;
}

// 音频编码函数
vector<vector<int>> encodeAudio(int n, vector<int>& audio) {
    // 将音频数据转化为视频数据
    int t = (n / 20) - 1;
    int h = 40;
    int w = 40;
    vector<vector<vector<int>>> video(t, vector<vector<int>>(3, vector<int>(h, vector<int>(w, 0))));

    for (int ti = 0; ti < t; ++ti) {
        int start = ti * 20;
        for (int i = 0; i < h; ++i) {
            for (int j = 0; j < w; ++j) {
                int audio_val = audio[start + j];
                if (i > audio_val) {
                    video[ti][0][i][j] = 255;
                    video[ti][1][i][j] = 255;
                    video[ti][2][i][j] = 255;
                } else {
                    video[ti][0][i][j] = 0;
                    video[ti][1][i][j] = 0;
                    video[ti][2][i][j] = 0;
                }
            }
        }
    }

    // 使用视频编码函数进行编码
    return encodeVideo(t, h, w, video);
}

// 文本编码函数
vector<vector<int>> encodeText(string& text) {
    // 分句
    vector<string> sentences;
    stringstream ss(text);
    string sentence;
    while (getline(ss, sentence, '.')) {
        if (!sentence.empty()) {
            sentences.push_back(sentence);
        }
    }

    // 词向量和位置编码
    vector<vector<int>> word_vectors;
    for (size_t i = 0; i < sentences.size(); ++i) {
        stringstream ss_sentence(sentences[i]);
        string word;
        vector<int> word_vector;
        int pos = 1;
        while (getline(ss_sentence, word, ' ')) {
            if (!word.empty()) {
                int sum = 0;
                for (char c : word) {
                    sum += (int)c;
                }
                word_vector.push_back(sum + pos);
                ++pos;
            }
        }
        word_vectors.push_back(word_vector);
    }

    // 句子向量
    vector<vector<int>> sentence_vectors;
    for (size_t i = 0; i < word_vectors.size(); ++i) {
        int sentence_value = 0;
        for (int val : word_vectors[i]) {
            sentence_value += val;
        }
        vector<int> sentence_vector(32, 0);
        for (int j = 0; j < 32; ++j) {
            sentence_vector[j] = (sentence_value * (j + 1)) % 1557;
        }
        sentence_vectors.push_back(sentence_vector);
    }

    return sentence_vectors;
}

