#include <bits/stdc++.h>
using namespace std;

// 计算最大公约数
int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

// 计算最小公倍数
int lcm(int a, int b) {
    return a * b / gcd(a, b);
}

// 生成质数表
vector<int> generate_primes(int limit) {
    vector<bool> is_prime(limit + 1, true);
    vector<int> primes;
    for (int i = 2; i <= limit; ++i) {
        if (is_prime[i]) {
            primes.push_back(i);
            for (int j = i * 2; j <= limit; j += i) {
                is_prime[j] = false;
            }
        }
    }
    return primes;
}

int main() {
    int N;
    cin >> N;

    // 生成质数表
    vector<int> primes = generate_primes(N);

    // 从大到小尝试分解
    vector<int> result;
    int remaining = N;
    for (int i = primes.size() - 1; i >= 0; --i) {
        while (remaining >= primes[i]) {
            result.push_back(primes[i]);
            remaining -= primes[i];
        }
    }

    // 如果还有剩余，用1补足
    while (remaining > 0) {
        result.push_back(1);
        remaining--;
    }

    // 计算LCM
    int max_lcm = 1;
    for (int num : result) {
        max_lcm = lcm(max_lcm, num);
    }

    // 输出字典序最小的解
    sort(result.begin(), result.end());
    for (int i = 0; i < result.size(); ++i) {
        cout << result[i] << " ";
    }
    cout << endl;

    return 0;
}

